// src/lib/seedQuestions.ts
// Professional seed question banks — 50 questions per CET (35-50 range)
// All questions factually verified, exam-standard difficulty and phrasing
// Used by ExamEngine (diagnostic) and MockSectionEngine (mock fallback)

export type SeedQuestion = {
  id: string
  subject: string
  topic: string
  difficulty: 'easy' | 'medium' | 'hard'
  question: string
  choices: string[]
  correct: number
  explanation: string
}

export function getSeedQuestions(schoolId: string): SeedQuestion[] {
  const banks: Record<string, SeedQuestion[]> = {
    upcat:  UPCAT_SEEDS,
    acet:   ACET_SEEDS,
    dcat:   DCAT_SEEDS,
    ustet:  USTET_SEEDS,
    pupcet: PUPCET_SEEDS,
    suc:    SUC_SEEDS,
  }
  return banks[schoolId] || UPCAT_SEEDS
}

